/** Delays (ms) for each reconnect attempt: 1s, 2s, 4s, 8s, 16s */
export const RECONNECT_DELAYS_MS = [1000, 2000, 4000, 8000, 16000];
const MAX_RECONNECT_ATTEMPTS = RECONNECT_DELAYS_MS.length;

let _reconnectAttempt = 0;
let _reconnectTimer: ReturnType<typeof setTimeout> | null = null;
let _reconnectCountdownTimer: ReturnType<typeof setInterval> | null = null;
let _reconnecting = false;   // true while a reconnect attempt is in flight
let _serverShutdown = false; // set by handle_server_shutdown before ws.close arrives

/**
 * Called by handle_server_shutdown so onclose knows not to reconnect.
 */
export function markServerShutdown(): void {
  _serverShutdown = true;
}

export function getCurrentWebSocketForTests(): WebSocket | null {
  return ws;
}

export function setCurrentWebSocketForTests(value: WebSocket | null): void {
  ws = value;
  Reflect.set(window, 'ws', value);
}

export function getCivserverportForTests(): string | null {
  return civserverport;
}

export function setCivserverportForTests(value: string | null): void {
  civserverport = value;
  Reflect.set(window, 'civserverport', value);
  store.civserverport = value ?? '';
}

export function forceCurrentWebSocketCloseForTests(
  code: number,
  reason = '',
  wasClean = false,
): { ok: boolean } {
  if (!ws?.onclose) return { ok: false };
  ws.onclose(new CloseEvent('close', { code, reason, wasClean }));
  return { ok: true };
}

export function getNetworkDebugState(): {
  readyState: number | 'no-ws';
  url: string | 'no-url';
  onmessageType: string | 'no-ws';
  civserverport: string | null;
} {
  return {
    readyState: ws ? ws.readyState : 'no-ws',
    url: ws ? ws.url : 'no-url',
    onmessageType: ws ? typeof ws.onmessage : 'no-ws',
    civserverport,
  };
}

/**
 * Reset all reconnect state — for use in tests only.
 * @internal
 */
export function _resetReconnectStateForTests(): void {
  stopReconnectTimers();
  _reconnectAttempt = 0;
  _reconnecting = false;
  _serverShutdown = false;
  store.connectionState = 'connected';
  disconnectOverlay.value = null;
}

/** Returns true if the ping timer is currently active — for use in tests only. @internal */
export function _isPingTimerActiveForTests(): boolean {
  return ping_timer != null;
}

/** Returns true if a packet worker is currently active — for use in tests only. @internal */
export function _isPacketWorkerActiveForTests(): boolean {
  return _packetWorker != null;
}

/** Returns true if the beforeunload handler is currently registered — for use in tests only. @internal */
export function _isBeforeUnloadHandlerRegisteredForTests(): boolean {
  return _beforeUnloadHandler != null;
}

function stopReconnectTimers(): void {
  if (_reconnectTimer != null) { clearTimeout(_reconnectTimer); _reconnectTimer = null; }
  if (_reconnectCountdownTimer != null) { clearInterval(_reconnectCountdownTimer); _reconnectCountdownTimer = null; }
}

function showConnectionBanner(text: string): void {
  connectionBanner.value = { text, showReload: false };
}

function clearConnectionBanner(): void {
  connectionBanner.value = null;
}

function startReconnect(): void {
  if (_reconnectAttempt >= MAX_RECONNECT_ATTEMPTS) {
    store.connectionState = 'disconnected';
    connectionBanner.value = { text: '⚠ Disconnected — ', showReload: true };
    disconnectOverlay.value = { phase: 'disconnected' };
    return;
  }

  store.connectionState = 'reconnecting';
  const delayMs = RECONNECT_DELAYS_MS[_reconnectAttempt];
  let countdown = Math.round(delayMs / 1000);

  const updateBanner = () => {
    showConnectionBanner(
      `⟳ Reconnecting in ${countdown}s… (attempt ${_reconnectAttempt + 1}/${MAX_RECONNECT_ATTEMPTS})`
    );
    disconnectOverlay.value = {
      phase: 'reconnecting',
      attempt: _reconnectAttempt,
      max: MAX_RECONNECT_ATTEMPTS,
      countdown,
    };
  };
  updateBanner();

  _reconnectCountdownTimer = setInterval(() => {
    countdown--;
    if (countdown > 0) updateBanner();
    else {
      clearInterval(_reconnectCountdownTimer!);
      _reconnectCountdownTimer = null;
    }
  }, 1000);

  _reconnectTimer = setTimeout(() => {
    _reconnectAttempt++;
    _reconnecting = true;
    websocket_init();
  }, delayMs);
}

/**
 * Skip the reconnect delay and attempt to reconnect immediately.
 * Called by DisconnectOverlay's "Try Now" button.
 */
export function reconnectNow(): void {
  stopReconnectTimers();
  _reconnecting = true;
  websocket_init();
}

/**
 * Reset reconnect counter and start fresh reconnect cycle.
 * Called by DisconnectOverlay's "Try Again" button (after exhaustion).
 */
export function tryAgain(): void {
  stopReconnectTimers();
  _reconnectAttempt = 0;
  _reconnecting = false;
  disconnectOverlay.value = null;
  startReconnect();
}

/**
 * Initialize the Network communication, by requesting a valid server port.
 * Always connects as observer.
 */
export function network_init(): void {
  if (!('WebSocket' in window)) {
    swal('WebSockets not supported', '', 'error');
    return;
  }

  // If civserverport is provided via URL param, connect directly (skip launcher)
  const urlParams = new URLSearchParams(window.location.search);
  const urlPort = urlParams.get('civserverport');
  if (urlPort) {
    setCivserverportForTests(urlPort);
    websocket_init();
    return;
  }

  fetch('/civclientlauncher?action=observe', { method: 'POST' })
    .then(response => {
      if (!response.ok) throw new Error('HTTP ' + response.status);
      return response.json().then(data => ({ data, response }));
    })
    .then(({ data, response }) => {
      let port: string | null = null;
      let result: string | null = null;

      // Try JSON body first (works with Railway CDN which strips custom headers)
      if (data && data.port != null) {
        port = String(data.port);
        result = data.result || 'success';
      }

      // Fallback to response headers
      if (!port) {
        port = response.headers.get('port');
        result = response.headers.get('result');
      }

      if (port != null && result === 'success') {
        setCivserverportForTests(port);
        websocket_init();
      } else {
        show_dialog_message('Network error', 'Invalid server port. Error: ' + result);
      }
    })
    .catch(error => {
      show_dialog_message(
        'Network error',
        'Unable to communicate with game launcher. Error: ' + error.message
      );
    });
}

/**
 * Initialize the WebSocket connection.
 * Includes the proxy patch: handles both single-packet and array-wrapped packets.
 */
export function websocket_init(): void {
  if (!_reconnecting) {
    blockUI('<h2>Please wait while connecting to the server.</h2>');
  }
  const proxyport = 1000 + parseFloat(civserverport!);
  const ws_protocol = window.location.protocol === 'https:' ? 'wss://' : 'ws://';
  const port = window.location.port ? ':' + window.location.port : '';
  const wsUrl = ws_protocol + window.location.hostname + port + '/civsocket/' + proxyport;
  console.log('[xbw] websocket_init: connecting to', wsUrl);
  setCurrentWebSocketForTests(new WebSocket(wsUrl));
  const currentWs = ws;
  if (currentWs == null) return;

  // Try to use Web Worker for JSON.parse; fall back to main-thread parsing.
  const worker = getPacketWorker();

  type AnyPacket = NonNullable<Parameters<typeof client_handle_packet>[0]>;
  const processPackets = (parsed: AnyPacket) => {
    if (typeof client_handle_packet === 'undefined' || !parsed) {
      return;
    }
    incrementDebugCounter('__xbwPacketCount', parsed.length);
    // Use larger chunks for big batches (tile replays) to reduce setTimeout overhead.
    // Each tile packet is a fast O(1) assign, so 200 per chunk still stays under ~2ms.
    const CHUNK = parsed.length > 200 ? 200 : 50;
    if (parsed.length <= CHUNK) {
      client_handle_packet!(parsed);
    } else {
      const processChunk = (start: number) => {
        client_handle_packet!(parsed.slice(start, start + CHUNK) as AnyPacket);
        if (start + CHUNK < parsed.length) {
          setTimeout(() => processChunk(start + CHUNK), 0);
        }
      };
      processChunk(0);
    }
  };

  const mainThreadParse = (event: MessageEvent) => {
    try {
      let parsed = JSON.parse(event.data);
      if (!Array.isArray(parsed)) parsed = [parsed];
      processPackets(parsed);
    } catch (e) {
      console.error('Failed to parse packet:', e);
    }
  };

  if (worker) {
    let workerReady = false;
    const pendingMessages: string[] = [];

    worker.onmessage = function (e: MessageEvent) {
      workerReady = true;
      if (e.data.error) {
        console.error('Packet worker parse error:', e.data.error);
      } else {
        processPackets(e.data.packets);
      }
    };
    // If the Worker script fails to load (e.g. 404), fall back to main-thread parsing.
    worker.onerror = function (ev: ErrorEvent) {
      ev.preventDefault();
      console.warn('Packet worker failed to load, falling back to main-thread parsing');
      _packetWorker = null;
      // Process any pending messages that were sent before the error
      if (ws) ws.onmessage = mainThreadParse;
      for (const msg of pendingMessages) {
        mainThreadParse({ data: msg } as MessageEvent);
      }
      pendingMessages.length = 0;
    };
    currentWs.onmessage = function (event: MessageEvent) {
      if (!workerReady && _packetWorker) {
        pendingMessages.push(event.data);
      }
      if (_packetWorker) {
        worker.postMessage(event.data);
      } else {
        mainThreadParse(event);
      }
    };
  } else {
    currentWs.onmessage = mainThreadParse;
  }

  currentWs.onopen = (e) => {
    console.log('[xbw] WebSocket onopen fired, readyState:', ws?.readyState, 'event:', e.type);
    // Successful (re)connection — reset reconnect state
    stopReconnectTimers();
    _reconnectAttempt = 0;
    _reconnecting = false;
    store.connectionState = 'connected';
    clearConnectionBanner();
    disconnectOverlay.value = null;
    check_websocket_ready();
  };

  currentWs.onclose = function (event: CloseEvent) {
    console.info(`[xbw] WebSocket closed code=${event.code} reason="${event.reason}"`);

    if (ping_timer) { clearInterval(ping_timer); ping_timer = null; }

    if (_beforeUnloadHandler) {
      window.removeEventListener('beforeunload', _beforeUnloadHandler);
      _beforeUnloadHandler = null;
    }

    turnDoneState.value = { ...turnDoneState.value, disabled: true };
    const saveBtn = document.getElementById('save_button') as HTMLButtonElement | null;
    if (saveBtn) saveBtn.disabled = true;

    // code 1000 = Normal Closure (intentional), 1001 = Going Away (page nav)
    const isCleanClose = event.code === 1000 || event.code === 1001;

    if (_serverShutdown || isCleanClose) {
      // Server explicitly shut down or user navigated away — do not reconnect
      _serverShutdown = false;
      store.connectionState = 'disconnected';
      if (!isCleanClose) {
        // handle_server_shutdown already showed a swal; only log here
        const ml = getMessageLog();
        if (ml != null) {
          ml.update({ event: E_LOG_ERROR, message: 'Server connection closed.' });
        }
      }
      return;
    }

    // Abnormal close (network drop, server crash, proxy timeout, etc.) — reconnect
    stopReconnectTimers();
    startReconnect();
  };

  currentWs.onerror = function (evt: Event) {
    // onclose always fires after onerror — let it handle reconnect
    console.error('[xbw] WebSocket error:', evt);
  };
}

/**
 * When the WebSocket connection is open and ready to communicate, then
 * send the first login message to the server.
 */
export async function check_websocket_ready(): Promise<void> {
  if (ws == null) return; // ws was nulled by network_stop() — abort retry loop
  if (ws.readyState === 1) {
    let sha_password: string | null = null;
    const stored_password = localStorage.getItem('password') ?? '';
    if (stored_password != null && stored_password !== '') {
      sha_password = encodeURIComponent(await sha512hex(stored_password));
    }

    const login_message = {
      pid: 4,
      username: store.username,
      capability: freeciv_version,
      version_label: '-dev',
      major_version: 3,
      minor_version: 3,
      patch_version: 90,
      port: civserverport,
      password: sha_password,
    };
    ws.send(JSON.stringify(login_message));

    // Leaving the page without saving can now be an issue.
    _beforeUnloadHandler = function (e: BeforeUnloadEvent) {
      e.preventDefault();
      return 'Do you really want to leave your nation behind now?';
    };
    window.addEventListener('beforeunload', _beforeUnloadHandler);

    // The connection is now up. Verify that it remains alive.
    ping_timer = setInterval(ping_check, pingtime_check);

    unblockUI();
  } else {
    setTimeout(check_websocket_ready, 500);
  }
}

/**
 * Stops network sync and cleans up all associated resources.
 */
export function network_stop(): void {
  stopReconnectTimers();
  _reconnectAttempt = 0;
  _reconnecting = false;
  // Stop ping timer
  if (ping_timer != null) { clearInterval(ping_timer); ping_timer = null; }
  // Remove beforeunload handler
  if (_beforeUnloadHandler != null) {
    window.removeEventListener('beforeunload', _beforeUnloadHandler);
    _beforeUnloadHandler = null;
  }
  // Terminate packet worker (prevents detached worker running after page nav)
  if (_packetWorker != null) { _packetWorker.terminate(); _packetWorker = null; }
  if (ws != null) ws.close();
  setCurrentWebSocketForTests(null);
}

/**
 * Sends a request to the server, with a JSON packet.
 */
export function send_request(packet_payload: string): void {
  if (ws != null && ws.readyState === 1 /* WebSocket.OPEN */) {
    ws.send(packet_payload);
  }
  if (store.debugActive) {
    clinet_last_send = new Date().getTime();
  }
}

/**
 * Debug timing collection.
 */
export function clinet_debug_collect(): void {
  const time_elapsed = new Date().getTime() - clinet_last_send;
  debug_client_speed_list.push(time_elapsed);
  clinet_last_send = new Date().getTime();
}

/**
 * Detect server disconnections, by checking the time since the last
 * ping packet from the server.
 */
export function ping_check(): void {
  const time_since_last_ping = new Date().getTime() - ping_last;
  if (time_since_last_ping > pingtime_check) {
    console.log(
      'Error: Missing PING message from server, indicates server connection problem.'
    );
  }
}

/**
 * Send the chat message to the server after a delay.
 */
export function send_message_delayed(message: string, delay: number): void {
  setTimeout(function () { send_message(message); }, delay);
}

/**
 * Sends a chat message to the server.
 */
export function send_message(message: string): void {
  sendChatMessage(message);
}
